const person = { name: 'Alice', age: 25 };

const personProxy = new Proxy(person, {
  get(target, property) {
    console.log(`Property "${property}" was accessed.`);
    return target[property];
  }
});

console.log(personProxy.name); // Logs: Property "name" was accessed. Then prints: Alice
console.log(personProxy.age);  // Logs: Property "age" was accessed. Then prints: 25

const user = { name: 'Bob', age: 30 };

const userProxy = new Proxy(user, {
  set(target, property, value) {
    if (property === 'age') {
      if (typeof value !== 'number' || value <= 0) {
        throw new Error('Age must be a positive number.');
      }
    }
    target[property] = value;
    return true; // indicate success
  }
});

userProxy.age = 35; // Works fine
// userProxy.age = -5; // Throws Error: Age must be a positive number.

const secretData = { publicInfo: 'Visible', secretInfo: 'Hidden' };

const proxyData = new Proxy(secretData, {
  has(target, property) {
    if (property === 'secretInfo') {
      return false; // pretend secretInfo does not exist
    }
    return property in target;
  },
  ownKeys(target) {
    // Filter out secretInfo from property list
    return Reflect.ownKeys(target).filter(key => key !== 'secretInfo');
  },
  get(target, property) {
    if (property === 'secretInfo') {
      return undefined;
    }
    return target[property];
  }
});

console.log('secretInfo' in proxyData); // false
console.log(Object.keys(proxyData)); // ['publicInfo']
console.log(proxyData.secretInfo);    // undefined

