function example(value: string | number) {
  if (typeof value === "string") {
    // TypeScript knows 'value' is a string here
    console.log(value.toUpperCase());
  } else {
    // Here 'value' is a number
    console.log(value.toFixed(2));
  }
}

interface Cat {
  name: string;
  meow: () => void;
}

interface Dog {
  name: string;
  bark: () => void;
}

// User-defined type predicate
function isCat(pet: Cat | Dog): pet is Cat {
  return (pet as Cat).meow !== undefined;
}

function speak(pet: Cat | Dog) {
  if (isCat(pet)) {
    pet.meow(); // Safe to call meow()
  } else {
    pet.bark(); // Safe to call bark()
  }
}

function greet(name: string | null) {
  if (name !== null) {
    // Inside this block, TypeScript knows 'name' is a string.
    console.log(`Hello, ${name.toUpperCase()}!`);
  } else {
    console.log('Hello, guest!');
  }
}

function formatValue(value: string | number) {
  if (typeof value === 'string') {
    // Here, TypeScript knows 'value' is a string
    return value.trim();
  } else {
    // Here, 'value' is a number
    return value.toFixed(2);
  }
}

from contextlib import contextmanager

@contextmanager
def open_file(filename, mode):
    try:
        f = open(filename, mode)
        print("File opened")
        yield f
    except Exception as e:
        print(f"Error occurred: {e}")
        raise
    finally:
        print("Closing file")
        f.close()

# Usage
try:
    with open_file('example.txt', 'r') as file:
        content = file.read()
        print(content)
except Exception:
    print("Handled file operation error.")

